import kotlin.test.assertEquals

class EventLoopYieldFairnessTest {
    @Test
    fun yieldPrefersExpiredDelayedTask() = runBlocking {
        val sequence = mutableListOf<String>()
        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            sequence += "first"
        }
        Thread.sleep(50)
        yield()
        sequence += "second"
        assertEquals(listOf("first", "second"), sequence)
